package com.eas.ui.admin;
import com.eas.config.Database; import com.eas.model.UserSession; import com.eas.service.AuditService; import com.eas.util.*; import java.awt.*; import java.sql.*; import javax.swing.*;
public class OvertimeApprovalPanel extends ReadOnlyQueryPanel { private final UserSession session; private final JTextField hours=new JTextField(8),remarks=new JTextField(22); public OvertimeApprovalPanel(UserSession s){super("Overtime Request Processing","SELECT * FROM v_overtime_monitoring ORDER BY id DESC","SELECT * FROM v_overtime_monitoring WHERE employee_no LIKE ? OR full_name LIKE ? OR status LIKE ? ORDER BY id DESC","overtime_requests");session=s;JPanel p=new JPanel();p.add(new JLabel("Approved Hours"));p.add(hours);p.add(new JLabel("Remarks"));p.add(remarks);JButton approve=UITheme.button("APPROVE");JButton reject=UITheme.button("REJECT");p.add(approve);p.add(reject);add(p,BorderLayout.SOUTH);approve.addActionListener(e->review("APPROVED"));reject.addActionListener(e->review("REJECTED"));}
 private void review(String st){int r=table.getSelectedRow();if(r<0){Dialogs.error(this,"Select an overtime request.");return;}int id=Integer.parseInt(table.getValueAt(r,0).toString());try(Connection c=Database.getConnection();PreparedStatement p=c.prepareStatement("UPDATE overtime_requests SET status=?,approved_hours=?,reviewed_by=?,reviewed_at=NOW(),admin_remarks=? WHERE id=? AND status='PENDING'")){p.setString(1,st);p.setString(2,"APPROVED".equals(st)?hours.getText().trim():"0");p.setInt(3,session.getId());p.setString(4,remarks.getText().trim());p.setInt(5,id);if(p.executeUpdate()==0)throw new SQLException("Only pending requests can be reviewed.");AuditService.log(session.getId(),st,"OVERTIME","Reviewed overtime #"+id);load("");}catch(Exception ex){Dialogs.error(this,ex.getMessage());}}
}
